import numpy as np

name = "max_cut"
description = "Partition a weighted graph to maximize the total cut edge weight."
x = np.array([0, 0, 0, 0, 0, 0, 0, 0])
linear = np.array(
    [5.800000000000001, 4.8, 6.6, 5.4, 5.300000000000001, 5.3, 6.800000000000001, 6.0]
)
quadratic = np.array(
    [
        [0.0, -2.0, 0.0, 0.0, -2.1, 0.0, 0.0, -1.7],
        [-2.0, 0.0, -1.5, 0.0, 0.0, -1.3, 0.0, 0.0],
        [0.0, -1.5, 0.0, -2.5, 0.0, 0.0, -2.6, 0.0],
        [0.0, 0.0, -2.5, 0.0, -1.0, 0.0, 0.0, -1.9],
        [-2.1, 0.0, 0.0, -1.0, 0.0, -2.2, 0.0, 0.0],
        [0.0, -1.3, 0.0, 0.0, -2.2, 0.0, -1.8, 0.0],
        [0.0, 0.0, -2.6, 0.0, 0.0, -1.8, 0.0, -2.4],
        [-1.7, 0.0, 0.0, -1.9, 0.0, 0.0, -2.4, 0.0],
    ]
)
objective = x.T @ quadratic @ x + linear @ x
metadata = {
    "template": "max_cut",
    "edges": [
        [0, 1, 2.0],
        [1, 2, 1.5],
        [2, 3, 2.5],
        [3, 4, 1.0],
        [4, 5, 2.2],
        [5, 6, 1.8],
        [6, 7, 2.4],
        [7, 0, 1.7],
        [0, 4, 2.1],
        [1, 5, 1.3],
        [2, 6, 2.6],
        [3, 7, 1.9],
    ],
    "expected_optimal_value": 20.3,
}
maximize(objective)  # type: ignore[name-defined]  # noqa: F821
